import{_ as i,o as s,c as e,ak as l,al as t}from"./chunks/framework.B9OfcISu.js";const u=JSON.parse('{"title":"Arch Linux","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"setup/os/arch_linux.md","filePath":"setup/os/arch_linux.md"}'),n={name:"setup/os/arch_linux.md"};function o(h,a,c,r,d,p){return s(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="arch-linux" tabindex="-1"><img src="'+t+`" style="display:inline-block;vertical-align:middle;height:48px;margin-right:8px;"> Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h1><p>Arch Linux is a &quot;Do It Yourself&quot; Linux distribution, so its most useful commands focus heavily on package management and system maintenance. While standard Linux commands like <code>ls</code>, <code>cd</code>, and <code>grep</code> apply, the soul of Arch lies in other system-specific utilities.</p><h2 id="yay" tabindex="-1">yay <a class="header-anchor" href="#yay" aria-label="Permalink to “yay”">​</a></h2><p><code>yay</code> is a popular helper for Arch Linux. It simplifies the process of installing software from the Arch User Repository (AUR) by automating the manual steps of cloning, building, and resolving dependencies.</p><p>Since yay is an AUR package itself, you cannot install it via <code>pacman</code> directly on a fresh Arch install. You must build it manually once.</p><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h3><ol><li>Install Prerequisites</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --needed</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> base-devel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span></span></code></pre></div><ol start="2"><li>Clone and Build</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://aur.archlinux.org/yay.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yay</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">makepkg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -si</span></span></code></pre></div><h3 id="essential-commands" tabindex="-1">Essential Commands <a class="header-anchor" href="#essential-commands" aria-label="Permalink to “Essential Commands”">​</a></h3><ul><li>Updates: <code>yay</code></li><li>Installing Packages: <code>yay -S package_name</code></li><li>Searching: <code>yay -Ss search_term</code></li><li>Removing Packages: <code>yay -Rns package_name</code></li><li>Clean cached build files: <code>yay -Sc</code></li><li>Remove orphan/unneeded dependencies: <code>yay -Yc</code></li><li>System stats: <code>yay -Ps</code></li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>If a package fails to build, check the package page on <a href="https://aur.archlinux.org/" target="_blank" rel="noreferrer">https://aur.archlinux.org/</a>. Often, other users have posted a fix in the comments.</p></div>`,13)])])}const g=i(n,[["render",o]]);export{u as __pageData,g as default};
